import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Registration.css';

function Register() {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    password: '', // New Password Field
    serviceType: 'Web Development',
    paymentMethod: 'Online',
    transactionId: '',
    projectDetails: 'Standard Project Request'
  });

  const [price, setPrice] = useState(0);

  useEffect(() => {
    const prices = {
      'Web Development': 5000,
      'UI/UX Design': 3000,
      'App Development': 8000,
      'Assignment Support': 500,
      'PPT Design': 300,
      'Report Writing': 400
    };
    setPrice(prices[formData.serviceType]);
  }, [formData.serviceType]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // 1. Password Length Validation (Min 8 Characters)
    if (formData.password.length < 8) {
      alert("❌ Password must be at least 8 characters long!");
      return;
    }

    try {
      // Sending data to Backend (Port 5000)
      const res = await axios.post('http://localhost:5000/api/hire', formData);
      
      if (res.status === 201) {
        alert("✅ Registration Successful! You can now login with your password.");
        // Reset Form after success
        setFormData({ 
          fullName: '', 
          email: '', 
          password: '', 
          serviceType: 'Web Development', 
          paymentMethod: 'Online', 
          transactionId: '', 
          projectDetails: 'Standard Project Request' 
        });
      }
    } catch (err) {
      console.error(err);
      alert("❌ Registration Failed. Please make sure the server is running on port 5000.");
    }
  };

  return (
    <div className="register-page bg-light py-5">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-md-6">
            <div className="card shadow border-0 p-4 rounded-4">
              <h3 className="fw-bold text-center mb-4">Service Registration</h3>
              <form onSubmit={handleSubmit}>
                
                {/* Full Name */}
                <div className="mb-3">
                  <label className="form-label fw-bold small">Full Name</label>
                  <input type="text" name="fullName" value={formData.fullName} className="form-control" placeholder="Enter your full name" required onChange={handleChange} />
                </div>

                {/* Email Address */}
                <div className="mb-3">
                  <label className="form-label fw-bold small">Email Address</label>
                  <input type="email" name="email" value={formData.email} className="form-control" placeholder="example@mail.com" required onChange={handleChange} />
                </div>

                {/* Password Field (Min 8 Chars) */}
                <div className="mb-3">
                  <label className="form-label fw-bold small text-primary">Create Password (Min 8 Characters)</label>
                  <input 
                    type="password" 
                    name="password" 
                    value={formData.password} 
                    className="form-control border-primary" 
                    placeholder="Choose a secure password" 
                    required 
                    minLength="8"
                    onChange={handleChange} 
                  />
                  <small className="text-muted">You will need this to login to your dashboard.</small>
                </div>

                {/* Select Service */}
                <div className="mb-3">
                  <label className="form-label fw-bold small">Select Service</label>
                  <select name="serviceType" className="form-select" onChange={handleChange} value={formData.serviceType}>
                    <option value="Web Development">Web Development</option>
                    <option value="UI/UX Design">UI/UX Design</option>
                    <option value="App Development">App Development</option>
                    <option value="Assignment Support">Assignment Support</option>
                    <option value="PPT Design">PPT Design</option>
                    <option value="Report Writing">Report Writing</option>
                  </select>
                </div>

                {/* Cost & Payment Method */}
                <div className="mt-4 p-3 border rounded bg-white shadow-sm">
                  <div className="d-flex justify-content-between align-items-center mb-3">
                    <h6 className="fw-bold m-0">Project Fee:</h6>
                    <span className="text-primary fw-bold fs-5">₹{price}</span>
                  </div>
                  
                  <label className="form-label fw-bold small">Payment Method</label>
                  <div className="d-flex gap-2 mb-3">
                    <button type="button" className={`btn btn-sm flex-fill ${formData.paymentMethod === 'Online' ? 'btn-primary' : 'btn-outline-primary'}`} onClick={() => setFormData({...formData, paymentMethod: 'Online'})}>Online</button>
                    <button type="button" className={`btn btn-sm flex-fill ${formData.paymentMethod === 'Cash' ? 'btn-primary' : 'btn-outline-primary'}`} onClick={() => setFormData({...formData, paymentMethod: 'Cash'})}>Cash</button>
                  </div>

                  {formData.paymentMethod === 'Online' && (
                    <div className="mt-2">
                      <input type="text" name="transactionId" className="form-control form-control-sm" placeholder="Enter Transaction ID" onChange={handleChange} required />
                    </div>
                  )}
                </div>

                <button type="submit" className="btn btn-primary w-100 fw-bold py-2 mt-4 shadow">
                  Register & Create Account
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
